<?php\n\nnamespace App\\Models;\n\nuse Illuminate\\Database\\Eloquent\\Model;\n\nclass PeminjamanAlat extends Model \{\n    protected $table = 'peminjaman_alat';\n    protected $fillable = [\n        'alat_id',\n        'nama_peminjam',\n        'kelas',\n        'jam_pelajaran',\n        'mata_pelajaran',\n        'tanggal_peminjaman',\n        'tanggal_kembali_target',\n        'tanggal_kembali_aktual',\n        'kondisi_saat_kembali',\n        'catatan_kerusakan',\n        'jumlah_denda',\n        'denda_sudah_bayar',\n        'status'\n    ];\n\n    public function equipment() \{\n        return $this->belongsTo(Equipment::class, 'alat_id');\n    \}  \n    \n    public function recordDenda() \{\n        return $this->hasMany(RecordDenda::class);\n    \}   \n\n}\n